+@page "/board"
+@using sv_7f251c3c169d49e4b3bb63d73af876bb.Services
+@inject ITaskService TaskService
+@rendermode InteractiveServer
+
+<PageTitle>Kanban Board</PageTitle>
+
+<h1>Project Board</h1>
+
+@if (_loading)
+{
+    <p><em>Loading tasks...</em></p>
+}
+else if (_error is not null)
+{
+    <div class="alert alert-danger">@_error</div>
+}
+else
+{
+    <KanbanStatsBar Tasks="_allTasks" />
+    <KanbanSearchBar SearchText="@_searchText" SearchTextChanged="OnSearchChanged" />
+
+    <div class="kanban-board">
+        @foreach (var column in _columns)
+        {
+            var columnTasks = GetFilteredTasksForStatus(column);
+            <KanbanColumn ColumnName="@column"
+                          Tasks="columnTasks"
+                          OnMoveTask="HandleMoveTask"
+                          OnAddTask="HandleAddTask"
+                          IsFirst="@(column == _columns[0])"
+                          IsLast="@(column == _columns[^1])" />
+        }
+    </div>
+}
+
+@code {
+    private List<TaskItem> _allTasks = new();
+    private string _searchText = string.Empty;
+    private bool _loading = true;
+    private string? _error;
+
+    private readonly string[] _columns = ["To Do", "In Progress", "Done"];
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadTasksAsync();
+    }
+
+    private async Task LoadTasksAsync()
+    {
+        try
+        {
+            _loading = true;
+            _error = null;
+            _allTasks = await TaskService.GetAllTasksAsync();
+        }
+        catch (Exception ex)
+        {
+            _error = $"Failed to load tasks: {ex.Message}";
+        }
+        finally
+        {
+            _loading = false;
+        }
+    }
+
+    private List<TaskItem> GetFilteredTasksForStatus(string status)
+    {
+        var tasks = _allTasks.Where(t => t.Status == status);
+        if (!string.IsNullOrWhiteSpace(_searchText))
+        {
+            tasks = tasks.Where(t => t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase));
+        }
+        return tasks.ToList();
+    }
+
+    private void OnSearchChanged(string text)
+    {
+        _searchText = text;
+    }
+
+    private async Task HandleMoveTask((int TaskId, string Direction) args)
+    {
+        var task = _allTasks.FirstOrDefault(t => t.Id == args.TaskId);
+        if (task is null) return;
+
+        var currentIndex = Array.IndexOf(_columns, task.Status);
+        var newIndex = args.Direction == "left" ? currentIndex - 1 : currentIndex + 1;
+
+        if (newIndex < 0 || newIndex >= _columns.Length) return;
+
+        var newStatus = _columns[newIndex];
+        try
+        {
+            await TaskService.UpdateTaskStatusAsync(args.TaskId, newStatus);
+            _allTasks = _allTasks.Select(t => t.Id == args.TaskId ? t with { Status = newStatus } : t).ToList();
+        }
+        catch (Exception ex)
+        {
+            _error = $"Failed to move task: {ex.Message}";
+        }
+    }
+
+    private async Task HandleAddTask((string Title, string Assignee, string Priority, DateTime DueDate, string Status) args)
+    {
+        try
+        {
+            var newTask = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
+            _allTasks.Add(newTask with { Status = args.Status });
+        }
+        catch (Exception ex)
+        {
+            _error = $"Failed to create task: {ex.Message}";
+        }
+    }
+}
