toolArgs.file_text:
.stats-bar {
    display: flex;
    gap: 1.5rem;
    padding: 1rem;
    background: #f8f9fa;
    border-radius: 8px;
    margin-bottom: 1rem;
    flex-wrap: wrap;
}

.stat-item {
    font-size: 0.9rem;
}

.stat-overdue {
    color: #dc3545;
}

.search-bar {
    margin-bottom: 1rem;
}

.search-bar input {
    width: 100%;
    max-width: 400px;
    padding: 0.5rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    font-size: 0.95rem;
}

.kanban-board {
    display: flex;
    gap: 1rem;
    align-items: flex-start;
}

::deep .kanban-column {
    flex: 1;
    background: #f1f3f5;
    border-radius: 8px;
    padding: 1rem;
    min-width: 250px;
}

::deep .column-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.75rem;
}

::deep .column-header h3 {
    margin: 0;
    font-size: 1.1rem;
}

::deep .task-count {
    background: #dee2e6;
    border-radius: 12px;
    padding: 0.1rem 0.6rem;
    font-size: 0.85rem;
}

::deep .task-card {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 0.75rem;
    margin-bottom: 0.5rem;
}

::deep .task-title {
    font-weight: 600;
    margin-bottom: 0.25rem;
}

::deep .task-assignee {
    font-size: 0.85rem;
    color: #6c757d;
    margin-bottom: 0.25rem;
}

::deep .priority-badge {
    display: inline-block;
    padding: 0.15rem 0.5rem;
    border-radius: 4px;
    font-size: 0.75rem;
    font-weight: 600;
    margin-bottom: 0.25rem;
}

::deep .priority-high {
    background: #dc3545;
    color: #fff;
}

::deep .priority-medium {
    background: #ffc107;
    color: #212529;
}

::deep .priority-low {
    background: #28a745;
    color: #fff;
}

::deep .task-due-date {
    font-size: 0.8rem;
    color: #6c757d;
    margin-bottom: 0.5rem;
}

::deep .task-actions {
    display: flex;
    gap: 0.5rem;
}

::deep .btn-move {
    font-size: 0.75rem;
    padding: 0.2rem 0.5rem;
    border: 1px solid #6c757d;
    border-radius: 4px;
    background: #fff;
    cursor: pointer;
}

::deep .btn-move:hover {
    background: #e9ecef;
}

::deep .btn-add-task {
    width: 100%;
    padding: 0.5rem;
    border: 1px dashed #adb5bd;
    border-radius: 4px;
    background: transparent;
    cursor: pointer;
    color: #6c757d;
    margin-top: 0.5rem;
}

::deep .btn-add-task:hover {
    background: #e9ecef;
}

::deep .add-task-form {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    margin-top: 0.5rem;
    padding: 0.75rem;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
}

::deep .add-task-form input,
::deep .add-task-form select {
    padding: 0.4rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    font-size: 0.9rem;
}

::deep .form-actions {
    display: flex;
    gap: 0.5rem;
}

::deep .btn-save {
    padding: 0.4rem 0.8rem;
    background: #0d6efd;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

::deep .btn-cancel {
    padding: 0.4rem 0.8rem;
    background: #6c757d;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

